func movementBadgeClass(mtype string) string {
	base := "inline-block rounded px-2 py-0.5 text-small font-medium "
	switch mtype {
	case "opening":
		return base + "bg-primary-soft text-primary"
	case "purchase":
		return base + "bg-success-soft text-success-hover"
	case "sale":
		return base + "bg-warning-soft text-warning"
	case "adjustment":
		return base + "bg-background text-text-muted border border-border"
	default:
		return base + "bg-background text-text-muted"
	}
}

func qtyDeltaClass(delta string) string {
	if len(delta) > 0 && delta[0] == '-' {
		return "text-danger"
	}
	return "text-success-hover"
}

